import sys

class Solution:
    def graphColoring(self, graph: list[list[int]], m: int) -> bool:
        v = len(graph)
        color = [0] * v

        def is_safe(node, c):
            for i in range(v):
                if graph[node][i] == 1 and color[i] == c:
                    return False
            return True

        def solve_coloring(node):
            if node == v:
                return True
            for c in range(1, m + 1):
                if is_safe(node, c):
                    color[node] = c
                    if solve_coloring(node + 1):
                        return True
                    color[node] = 0
            return False

        return solve_coloring(0)

if __name__ == '__main__':
    tokens = sys.stdin.read().split()
