#include <numeric>
#include <bits/stdc++.h>
using namespace std;

class Solution {
private:
    bool isSafe(int node, const vector<vector<int>>& graph, const vector<int>& color, int c) {
        for (int i = 0; i < graph.size(); i++) {
            if (graph[node][i] == 1 && color[i] == c) {
                return false;
            }
        }
        return true;
    }

    bool solveColoring(int node, const vector<vector<int>>& graph, vector<int>& color, int m) {
        if (node == graph.size()) return true;
        for (int c = 1; c <= m; c++) {
            if (isSafe(node, graph, color, c)) {
                color[node] = c;
                if (solveColoring(node + 1, graph, color, m)) return true;
                color[node] = 0;
            }
        }
        return false;
    }

public:
    bool graphColoring(vector<vector<int>>& graph, int m) {
        int v = graph.size();
        vector<int> color(v, 0);
        return solveColoring(0, graph, color, m); 
    }
};

int main() {
    ios::sync_with_stdio(false);
    cin.tie(nullptr);
    int v, e, m;
    if (!(cin >> v >> e >> m)) return 0;
    vector<vector<int>> graph(v, vector<int>(v, 0));
    for (int i = 0; i < e; i++) {
        int u, val;
        cin >> u >> val;
        graph[u][val] = 1;
        graph[val][u] = 1;
    }
    Solution sol;
    bool ans = sol.graphColoring(graph, m);
    cout << (ans ? "YES" : "NO") << "\n";
    return 0;
}
